#define LIMIT -999

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;

    if (k <= c)
        return c;
    else
        return k;
}

__attribute__((reqd_work_group_size(BLOCK_SIZE, 1, 1)))
void nw_kernel1(__global int* referrence,
                __global int* input_itemsets,
                __global int* output_itemsets,
                int max_cols,
                int penalty,
                int blk,
                int block_width,
                int worksize,
                int offset_r,
                int offset_c) {

    int b_index_x = get_global_id(0);

    if (b_index_x >= blk) return;

    int b_index_y = blk - 1 - b_index_x;

    int local_input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int local_reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int base_ref_row = b_index_y * BLOCK_SIZE + 1;
    int base_ref_col = b_index_x * BLOCK_SIZE + 1;
    int base_in_row = b_index_y * BLOCK_SIZE;
    int base_in_col = b_index_x * BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            local_reference_l[i * BLOCK_SIZE + j] = referrence[max_cols * (base_ref_row + i) + (base_ref_col + j)];
        }
    }

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            local_input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols * (base_in_row + i) + (base_in_col + j)];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            int val_diag = local_input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + (j - 1)] + local_reference_l[(i - 1) * BLOCK_SIZE + (j - 1)];
            int val_left = local_input_itemsets_l[i * (BLOCK_SIZE + 1) + (j - 1)] - penalty;
            int val_up = local_input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty;

            local_input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(val_diag, val_left, val_up);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols * (base_ref_row + i) + (base_ref_col + j)] = local_input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + (j + 1)];
        }
    }
}

